renderScript:
function (wrap, spec) {
  function load(url, g, cb) {
    if (window[g]) { cb(); return; }
    var s = document.createElement('script');
    s.src = url; s.onload = cb; document.head.appendChild(s);
  }
  load('https://cdn.jsdelivr.net/npm/d3@7/dist/d3.min.js', 'd3', function () { main(); });

  function main() {
    // ── Parse nodes & links ─────────────────────────────────────────────
    var nodes = (spec.nodes || []).map(function (n, i) {
      return { name: (n && n.name != null) ? String(n.name) : String(i) };
    });
    if (!nodes.length) {
      wrap.innerHTML = '';
      d3.select(wrap).append('div').style('padding', '16px')
        .style('font', '13px sans-serif').style('color', '#888')
        .text('Nodetrix: no nodes in data.');
      return;
    }
    var nameIdx = {};
    nodes.forEach(function (n, i) { if (!(n.name in nameIdx)) nameIdx[n.name] = i; });
    function resolve(v) {
      if (typeof v === 'number' && v >= 0 && v < nodes.length) return v;
      var k = String(v); return (k in nameIdx) ? nameIdx[k] : -1;
    }
    var links = [];
    var selfW = {};   // node index -> total self-loop weight (shown on the matrix diagonal)
    (spec.links || []).forEach(function (l) {
      var s = resolve(l.source), t = resolve(l.target);
      if (s < 0 || t < 0) return;
      var v = (l.value == null ? 1 : +l.value);
      if (s === t) { selfW[s] = (selfW[s] || 0) + v; return; }
      links.push({ source: s, target: t, value: v });
    });
    var adj = nodes.map(function () { return {}; });
    var degree = nodes.map(function () { return 0; });
    links.forEach(function (l) {
      adj[l.source][l.target] = (adj[l.source][l.target] || 0) + l.value;
      adj[l.target][l.source] = (adj[l.target][l.source] || 0) + l.value;
      degree[l.source] += l.value; degree[l.target] += l.value;
    });

    // ── Grouping algorithms (each returns an array of clusters of node indices) ──
    function groupsFromLabels(label) {
      var groups = {};
      label.forEach(function (lb, i) { (groups[lb] = groups[lb] || []).push(i); });
      return Object.keys(groups).map(function (k) { return groups[k]; });
    }
    function clustersLabelProp() {
      var label = nodes.map(function (_, i) { return i; });
      var order = nodes.map(function (_, i) { return i; });
      var seed = 2166136261;
      nodes.forEach(function (n) {
        var nm = n.name;
        for (var i = 0; i < nm.length; i++) seed = Math.imul(seed ^ nm.charCodeAt(i), 16777619);
      });
      seed = seed || 1;
      var rng = function () { seed ^= seed << 13; seed ^= seed >>> 17; seed ^= seed << 5; return (seed >>> 0) / 4294967296; };
      for (var it = 0; it < 14; it++) {
        for (var a = order.length - 1; a > 0; a--) {
          var b = Math.floor(rng() * (a + 1)), tmp = order[a]; order[a] = order[b]; order[b] = tmp;
        }
        var changed = false;
        order.forEach(function (i) {
          var cnt = {}, best = label[i], bestv = 0;
          for (var j in adj[i]) { var lb = label[j]; cnt[lb] = (cnt[lb] || 0) + adj[i][j]; if (cnt[lb] > bestv) { bestv = cnt[lb]; best = lb; } }
          if (best !== label[i]) { label[i] = best; changed = true; }
        });
        if (!changed) break;
      }
      return groupsFromLabels(label);
    }
    function clustersLouvain() {
      var n = nodes.length, community = nodes.map(function (_, i) { return i; });
      var totW = 0; links.forEach(function (l) { totW += l.value; });
      if (totW <= 0) return groupsFromLabels(community);
      var ki = degree.slice(), commTot = ki.slice(), m = totW, improved = true, iters = 20;
      while (improved && iters-- > 0) {
        improved = false;
        for (var id = 0; id < n; id++) {
          var curr = community[id], kiv = ki[id], sumTotCurr = commTot[curr], kin = 0, neigh = {};
          for (var nid in adj[id]) {
            var nc = community[nid], w = adj[id][nid];
            if (nc === curr) kin += w; else neigh[nc] = (neigh[nc] || 0) + w;
          }
          var bestGain = 1e-9, bestC = curr;
          for (var c in neigh) {
            var k = neigh[c], stn = commTot[c];
            var gain = k - (stn * kiv) / (2 * m) - kin + ((sumTotCurr - kiv) * kiv) / (2 * m);
            if (gain > bestGain) { bestGain = gain; bestC = +c; }
          }
          if (bestC !== curr) { commTot[curr] -= kiv; commTot[bestC] += kiv; community[id] = bestC; improved = true; }
        }
      }
      return groupsFromLabels(community);
    }
    function clustersComponents() {
      var seen = nodes.map(function () { return false; }), comps = [];
      for (var i = 0; i < nodes.length; i++) {
        if (seen[i]) continue;
        var stack = [i], comp = []; seen[i] = true;
        while (stack.length) {
          var u = stack.pop(); comp.push(u);
          for (var v in adj[u]) { if (!seen[v]) { seen[v] = true; stack.push(+v); } }
        }
        comps.push(comp);
      }
      return comps;
    }
    function clustersSpec() {
      if (spec.clusters && spec.clusters.length) {
        var used = {};
        var cs = spec.clusters.map(function (c) {
          return c.map(resolve).filter(function (i) { return i >= 0; });
        }).filter(function (c) { return c.length; });
        cs.forEach(function (c) { c.forEach(function (i) { used[i] = 1; }); });
        nodes.forEach(function (_, i) { if (!used[i]) cs.push([i]); });
        return cs;
      }
      return clustersLouvain();
    }
    // Order a cluster's members so strongly-connected nodes sit adjacent (nicer matrix).
    function orderCluster(members) {
      if (members.length <= 2) return members.slice();
      var set = {}; members.forEach(function (i) { set[i] = 1; });
      var localDeg = {};
      members.forEach(function (i) { var s = 0; for (var j in adj[i]) if (set[j]) s += adj[i][j]; localDeg[i] = s; });
      var order = members.slice().sort(function (a, b) { return localDeg[b] - localDeg[a]; });
      var pos = {}; order.forEach(function (e, i) { pos[e] = i; });
      for (var it = 0; it < 12; it++) {
        var bary = {};
        order.forEach(function (e) {
          var sum = 0, w = 0;
          for (var o in adj[e]) { if (!set[o]) continue; sum += pos[o] * adj[e][o]; w += adj[e][o]; }
          bary[e] = w > 0 ? (pos[e] + sum / w) / 2 : pos[e];
        });
        order.sort(function (a, b) { return (bary[a] - bary[b]) || (pos[a] - pos[b]); });
        order.forEach(function (e, i) { pos[e] = i; });
      }
      return order;
    }

    // ── Settings / state ────────────────────────────────────────────────
    var hasSpecClusters = !!(spec.clusters && spec.clusters.length);
    var settings = {
      grouping: hasSpecClusters ? 'spec' : 'louvain',
      maxMatrices: (spec.maxMatrices != null) ? +spec.maxMatrices : 12,
      maxDim: (spec.maxMatrixDim != null) ? Math.max(3, +spec.maxMatrixDim) : 24,
      cellScale: 1,
      showLabels: true,
      linkOpacity: 0.7,
      dropOrphans: !!spec.dropOrphans
    };
    var MINM = 3;

    // ── Build DOM scaffold (mainArea + control panel), modelled on timearcs ──
    wrap.innerHTML = '';
    wrap.style.cssText = 'user-select:none;display:flex;flex-direction:column;overflow:hidden;width:100%;box-sizing:border-box;';
    var fitWrap = function () {
      var ph = wrap.parentNode ? (wrap.parentNode.clientHeight || 0) : 0;
      wrap.style.height = (ph > 200 ? ph : 480) + 'px';
    };
    fitWrap();

    var hdr = document.createElement('div');
    hdr.style.cssText = 'flex-shrink:0;background:var(--bg,#fff);padding:4px 0 2px;position:relative;z-index:5;';
    wrap.appendChild(hdr);
    if (spec.title) {
      var ttl = document.createElement('div');
      ttl.style.cssText = 'text-align:center;font-size:13px;font-weight:500;color:var(--text,#333);margin-bottom:2px;';
      ttl.textContent = spec.title;
      hdr.appendChild(ttl);
    }
    var noteEl = document.createElement('div');
    noteEl.style.cssText = 'text-align:center;font-size:10px;color:var(--text3,#999);margin-bottom:2px;';
    hdr.appendChild(noteEl);

    var row = document.createElement('div');
    row.style.cssText = 'position:relative;flex:1 1 auto;min-height:200px;overflow:hidden;';
    wrap.appendChild(row);

    var PANEL_W = 172;
    var mainArea = document.createElement('div');
    mainArea.style.cssText = 'position:absolute;left:0;right:' + PANEL_W + 'px;top:0;bottom:0;overflow:hidden;background:var(--bg,#fff);';
    row.appendChild(mainArea);

    var ctrlPanel = document.createElement('div');
    ctrlPanel.style.cssText = 'position:absolute;right:0;top:0;bottom:0;width:' + PANEL_W + 'px;border-left:1px solid var(--border2,#ccc);overflow-y:auto;padding:8px 8px;background:var(--bg,#fff);display:flex;flex-direction:column;gap:3px;box-sizing:border-box;';
    row.appendChild(ctrlPanel);

    // Floating info box for clicked cells / nodes
    var infoBox = document.createElement('div');
    infoBox.style.cssText = 'position:absolute;left:8px;top:8px;max-width:230px;background:var(--bg,#fff);border:1px solid var(--border2,#ccc);border-radius:5px;box-shadow:0 2px 8px rgba(0,0,0,0.15);padding:8px 22px 8px 10px;font:11px/1.5 sans-serif;color:var(--text,#333);display:none;z-index:10;';
    var infoBody = document.createElement('div');
    var infoClose = document.createElement('span');
    infoClose.textContent = '×';
    infoClose.style.cssText = 'position:absolute;top:2px;right:6px;cursor:pointer;font-size:15px;line-height:1;color:var(--text3,#999);';
    infoClose.onclick = function () { hideInfo(); };
    infoBox.appendChild(infoBody); infoBox.appendChild(infoClose);
    mainArea.appendChild(infoBox);
    function showInfo(html) { infoBody.innerHTML = html; infoBox.style.display = 'block'; }
    function hideInfo() { infoBox.style.display = 'none'; }

    // ── Control panel widgets ───────────────────────────────────────────
    var labelStyle = 'font-size:10px;font-weight:600;color:var(--text3,#999);letter-spacing:0.5px;text-transform:uppercase;margin:2px 0;';
    function sectionLabel(text) {
      var d = document.createElement('div'); d.style.cssText = labelStyle; d.textContent = text; ctrlPanel.appendChild(d); return d;
    }
    function sep() {
      var d = document.createElement('div'); d.style.cssText = 'height:1px;background:var(--border2,#eee);margin:5px 0;'; ctrlPanel.appendChild(d);
    }
    function mkBtn(lbl) {
      var b = document.createElement('button');
      b.style.cssText = 'display:block;width:100%;text-align:left;font-size:11px;padding:3px 6px;border-radius:3px;border:1px solid transparent;background:transparent;color:var(--text,#444);cursor:pointer;';
      b.textContent = lbl; return b;
    }
    function mkSlider(min, max, step, val) {
      var holder = document.createElement('div');
      holder.style.cssText = 'display:flex;align-items:center;gap:6px;';
      var s = document.createElement('input');
      s.type = 'range'; s.min = min; s.max = max; s.step = step; s.value = val;
      s.style.cssText = 'flex:1;cursor:pointer;';
      var v = document.createElement('span');
      v.style.cssText = 'font-size:10px;color:var(--text3,#999);min-width:26px;text-align:right;';
      v.textContent = val;
      holder.appendChild(s); holder.appendChild(v);
      return { holder: holder, slider: s, valEl: v };
    }
    function mkToggle(lbl, val) {
      var itm = document.createElement('label');
      itm.style.cssText = 'display:flex;align-items:center;gap:6px;font-size:11px;color:var(--text2,#666);cursor:pointer;padding:2px 0;';
      var cb = document.createElement('input'); cb.type = 'checkbox'; cb.checked = val; cb.style.cursor = 'pointer';
      itm.appendChild(cb); itm.appendChild(document.createTextNode(lbl));
      return { el: itm, cb: cb };
    }

    // GROUPING
    sectionLabel('GROUPING');
    var methodBtns = {};
    var methods = [
      { id: 'louvain', label: 'Louvain' },
      { id: 'labelprop', label: 'Label Prop' },
      { id: 'components', label: 'Components' }
    ];
    if (hasSpecClusters) methods.unshift({ id: 'spec', label: 'Provided clusters' });
    methods.forEach(function (mth) {
      var b = mkBtn(mth.label);
      b.onclick = function () { settings.grouping = mth.id; rebuild(); };
      methodBtns[mth.id] = b; ctrlPanel.appendChild(b);
    });

    // VISUAL SETTINGS
    sep();
    sectionLabel('CELL SIZE');
    var cellCtl = mkSlider(0.5, 2.5, 0.1, 1);
    ctrlPanel.appendChild(cellCtl.holder);
    cellCtl.slider.addEventListener('input', function () {
      settings.cellScale = +cellCtl.slider.value; cellCtl.valEl.textContent = (+cellCtl.slider.value).toFixed(1); rebuild();
    });

    sectionLabel('MAX MATRIX SIZE');
    var dimCtl = mkSlider(6, 40, 1, settings.maxDim);
    ctrlPanel.appendChild(dimCtl.holder);
    dimCtl.slider.addEventListener('input', function () {
      settings.maxDim = +dimCtl.slider.value; dimCtl.valEl.textContent = dimCtl.slider.value; rebuild();
    });

    sectionLabel('MAX MATRICES');
    var matCtl = mkSlider(1, 30, 1, Math.min(30, settings.maxMatrices));
    ctrlPanel.appendChild(matCtl.holder);
    matCtl.slider.addEventListener('input', function () {
      settings.maxMatrices = +matCtl.slider.value; matCtl.valEl.textContent = matCtl.slider.value; rebuild();
    });

    sectionLabel('LINK OPACITY');
    var opCtl = mkSlider(0.1, 1, 0.05, settings.linkOpacity);
    ctrlPanel.appendChild(opCtl.holder);
    opCtl.slider.addEventListener('input', function () {
      settings.linkOpacity = +opCtl.slider.value; opCtl.valEl.textContent = (+opCtl.slider.value).toFixed(2); restyle();
    });

    sep();
    var lblToggle = mkToggle('Show labels', settings.showLabels);
    ctrlPanel.appendChild(lblToggle.el);
    lblToggle.cb.addEventListener('change', function () { settings.showLabels = lblToggle.cb.checked; restyle(); });
    var orphToggle = mkToggle('Drop orphan nodes', settings.dropOrphans);
    ctrlPanel.appendChild(orphToggle.el);
    orphToggle.cb.addEventListener('change', function () { settings.dropOrphans = orphToggle.cb.checked; rebuild(); });

    sep();
    var resetBtn = mkBtn('Reset view');
    resetBtn.style.border = '1px solid var(--border2,#ccc)';
    resetBtn.style.textAlign = 'center';
    resetBtn.onclick = function () { zoomTransform = d3.zoomIdentity; if (svgSel && zoomBeh) svgSel.call(zoomBeh.transform, d3.zoomIdentity); };
    ctrlPanel.appendChild(resetBtn);

    function updateMethodButtons() {
      Object.keys(methodBtns).forEach(function (id) {
        var active = id === settings.grouping;
        var b = methodBtns[id];
        b.style.background = active ? 'var(--accent-bg,#e8f0fe)' : 'transparent';
        b.style.color = active ? 'var(--accent-text,#1a73e8)' : 'var(--text,#444)';
        b.style.borderColor = active ? 'var(--accent,#1a73e8)' : 'transparent';
        b.style.fontWeight = active ? '600' : 'normal';
      });
    }

    // ── Layout build ────────────────────────────────────────────────────
    var blocks = [], within = {}, bridges = [];
    var svgSel = null, gRoot = null, gB = null, gN = null, zoomBeh = null, sim = null;
    var zoomTransform = d3.zoomIdentity;
    var blockSel = null, bridgeSel = null;

    function compute() {
      var raw;
      if (settings.grouping === 'louvain') raw = clustersLouvain();
      else if (settings.grouping === 'labelprop') raw = clustersLabelProp();
      else if (settings.grouping === 'components') raw = clustersComponents();
      else raw = clustersSpec();

      var W = mainArea.clientWidth || 600, H = mainArea.clientHeight || 400;
      var MAXMAT = settings.maxMatrices, MAXDIM = Math.max(MINM, settings.maxDim);
      var sel = raw.filter(function (c) { return c.length >= MINM; })
        .sort(function (a, b) { return b.length - a.length; }).slice(0, MAXMAT);
      var matrixClusters = [];
      sel.forEach(function (c) {
        var ordered = orderCluster(c);
        if (ordered.length <= MAXDIM) matrixClusters.push(ordered);
        else for (var k = 0; k < ordered.length; k += MAXDIM) matrixClusters.push(ordered.slice(k, k + MAXDIM));
      });
      var nodeCluster = {};
      matrixClusters.forEach(function (c, ci) { c.forEach(function (ni) { nodeCluster[ni] = ci; }); });

      blocks = [];
      matrixClusters.forEach(function (c) {
        var dim = c.length;
        var cs = Math.max(5, Math.min(20, Math.floor((Math.min(W, H) * 0.45) / dim))) * settings.cellScale;
        cs = Math.max(3, cs);
        blocks.push({ type: 'matrix', members: c.slice(), cellSize: cs });
      });
      nodes.forEach(function (n, ni) {
        if (ni in nodeCluster) return;
        if (settings.dropOrphans) {
          var hit = false;
          for (var j in adj[ni]) { if (j in nodeCluster) { hit = true; break; } }
          if (!hit) return;
        }
        blocks.push({ type: 'node', members: [ni] });
      });

      var nodeBlock = {};
      blocks.forEach(function (b, bi) { b.members.forEach(function (ni) { nodeBlock[ni] = bi; }); });
      blocks.forEach(function (b) {
        if (b.type === 'matrix') {
          b.dim = b.members.length;
          b.w = b.dim * b.cellSize; b.h = b.w;
          b.r = b.w * 0.72;
        } else { b.r = 9; b.w = 18; b.h = 18; }
      });

      within = {};
      blocks.forEach(function (b, bi) { if (b.type === 'matrix') within[bi] = {}; });
      var bridgeMap = {};
      links.forEach(function (l) {
        var bs = nodeBlock[l.source], bt = nodeBlock[l.target];
        if (bs == null || bt == null) return;
        if (bs === bt) {
          if (blocks[bs].type === 'matrix') {
            var m = within[bs];
            m[l.source + '_' + l.target] = (m[l.source + '_' + l.target] || 0) + l.value;
            m[l.target + '_' + l.source] = (m[l.target + '_' + l.source] || 0) + l.value;
          }
        } else {
          var k = Math.min(bs, bt) + '_' + Math.max(bs, bt);
          bridgeMap[k] = (bridgeMap[k] || 0) + l.value;
        }
      });
      bridges = Object.keys(bridgeMap).map(function (k) {
        var p = k.split('_'); return { source: +p[0], target: +p[1], value: bridgeMap[k] };
      });
      // Self-loops populate the matrix diagonal so a node connecting to itself shows data.
      blocks.forEach(function (b, bi) {
        if (b.type !== 'matrix') return;
        b.members.forEach(function (ni) { if (selfW[ni]) within[bi][ni + '_' + ni] = selfW[ni]; });
      });

      var nMat = blocks.filter(function (b) { return b.type === 'matrix'; }).length;
      var nNode = blocks.length - nMat;
      noteEl.textContent = nMat + ' matri' + (nMat === 1 ? 'x' : 'ces') + ', ' + nNode + ' single node' + (nNode === 1 ? '' : 's') +
        ' — drag blocks, scroll to zoom, click a cell for details';
    }

    function rebuild() {
      updateMethodButtons();
      compute();
      draw();
    }

    function draw() {
      hideInfo();
      var W = mainArea.clientWidth || 600, H = mainArea.clientHeight || 400;
      mainArea.querySelectorAll('svg').forEach(function (s) { s.remove(); });

      svgSel = d3.select(mainArea).insert('svg', ':first-child')
        .attr('width', W).attr('height', H).style('cursor', 'grab').style('display', 'block');
      gRoot = svgSel.append('g');
      zoomBeh = d3.zoom().scaleExtent([0.1, 5]).on('zoom', function (e) {
        zoomTransform = e.transform; gRoot.attr('transform', e.transform);
      });
      svgSel.call(zoomBeh);
      svgSel.on('dblclick.zoom', null);
      svgSel.call(zoomBeh.transform, zoomTransform);

      gB = gRoot.append('g'); gN = gRoot.append('g');

      var maxBridge = d3.max(bridges, function (d) { return d.value; }) || 1;
      var bw = d3.scaleLinear().domain([0, maxBridge]).range([1, 6]);
      bridgeSel = gB.selectAll('line').data(bridges).enter().append('line')
        .attr('stroke', '#9ba6c4').attr('stroke-opacity', settings.linkOpacity)
        .attr('stroke-width', function (d) { return bw(d.value); });
      bridgeSel.append('title').text(function (d) {
        // After forceLink runs (e.g. on redraw) d.source/target are block objects, not indices.
        return blockLabel(blockOf(d.source)) + ' ↔ ' + blockLabel(blockOf(d.target)) + '  ·  weight ' + d.value;
      });

      blockSel = gN.selectAll('g').data(blocks).enter().append('g');
      blockSel.each(function (b, bi) { drawBlock(d3.select(this), b, bi); });

      if (sim) sim.stop();
      sim = d3.forceSimulation(blocks)
        .force('charge', d3.forceManyBody().strength(-450))
        .force('link', d3.forceLink(bridges).distance(function (d) { return 60 + d.source.r + d.target.r; }).strength(0.3))
        .force('center', d3.forceCenter(W / 2, H / 2))
        .force('collide', d3.forceCollide().radius(function (d) { return d.r + 18; }));

      blockSel.call(d3.drag()
        .on('start', function (e, d) { if (!e.active) sim.alphaTarget(0.3).restart(); d.fx = d.x; d.fy = d.y; })
        .on('drag', function (e, d) { d.fx = e.x; d.fy = e.y; })
        .on('end', function (e, d) { if (!e.active) sim.alphaTarget(0); d.fx = null; d.fy = null; }));

      sim.on('tick', function () {
        blockSel.attr('transform', function (b) { return 'translate(' + b.x + ',' + b.y + ')'; });
        bridgeSel.attr('x1', function (d) { return d.source.x; }).attr('y1', function (d) { return d.source.y; })
          .attr('x2', function (d) { return d.target.x; }).attr('y2', function (d) { return d.target.y; });
      });

      restyle();
    }

    function blockOf(ref) { return (ref && typeof ref === 'object') ? ref : blocks[ref]; }
    function blockLabel(b) {
      if (!b) return '?';
      if (b.type === 'node') return nodes[b.members[0]].name;
      return 'Matrix (' + b.members.length + ' nodes)';
    }

    function drawBlock(sel, b, bi) {
      if (b.type === 'matrix') {
        var m = within[bi], cs = b.cellSize, mem = b.members, maxv = 1;
        mem.forEach(function (r) { mem.forEach(function (c) { var v = m[r + '_' + c] || 0; if (v > maxv) maxv = v; }); });
        // Pow scale (exponent < 1) so low-weight links are still visible, not washed out to near-white.
        var color = d3.scalePow().exponent(0.6).domain([0, maxv]).range(['#cdd3f5', '#3b318f']);
        var grid = sel.append('g').attr('class', 'nx-grid').attr('transform', 'translate(' + (-b.w / 2) + ',' + (-b.h / 2) + ')');
        mem.forEach(function (r, ri) {
          mem.forEach(function (c, ci) {
            var self = ri === ci, v = m[r + '_' + c] || 0;
            var rect = grid.append('rect')
              .attr('x', ci * cs).attr('y', ri * cs).attr('width', cs).attr('height', cs)
              .attr('fill', v > 0 ? color(v) : '#ffffff')
              .attr('stroke', '#d7d9ea').attr('stroke-width', 0.5)
              .style('cursor', 'pointer');
            rect.append('title').text((self ? nodes[r].name + ' ↺ itself' : nodes[r].name + ' → ' + nodes[c].name) +
              (v > 0 ? '  ·  weight ' + v : self ? '  ·  no self-link' : '  ·  no link'));
            (function (rr, cc, vv, isSelf) {
              rect.on('mouseenter', function () { d3.select(this).attr('stroke', '#3b318f').attr('stroke-width', 1.5); })
                .on('mouseleave', function () { d3.select(this).attr('stroke', '#d7d9ea').attr('stroke-width', 0.5); })
                .on('click', function (ev) {
                  ev.stopPropagation();
                  showInfo('<b>' + (isSelf ? 'Self-connection' : 'Cell') + '</b><br>' +
                    (isSelf ? 'Node: <b>' + esc(nodes[rr].name) + '</b>'
                            : 'Row: <b>' + esc(nodes[rr].name) + '</b><br>Col: <b>' + esc(nodes[cc].name) + '</b>') +
                    '<br>' + (isSelf ? 'Self weight' : 'Link weight') + ': <b>' + vv + '</b>' +
                    (vv === 0 ? ' (no ' + (isSelf ? 'self-loop' : 'direct link') + ')' : '') +
                    '<br><span style="color:var(--text3,#999)">deg(' + esc(nodes[rr].name) + ')=' + degree[rr] +
                    (isSelf ? '' : ', deg(' + esc(nodes[cc].name) + ')=' + degree[cc]) + '</span>');
                });
            })(r, c, v, self);
          });
        });
        // Row labels (left) + column labels (top, rotated). Use --text for strong contrast
        // against the dark/light canvas, with a halo so they stay legible over cells too.
        var lblG = sel.append('g').attr('class', 'nx-labels').attr('transform', 'translate(' + (-b.w / 2) + ',' + (-b.h / 2) + ')');
        var fs = Math.max(8, Math.min(12, cs * 0.82));
        function lbl(node, x, y, anchor, rot) {
          var t = lblG.append('text').attr('x', x).attr('y', y)
            .attr('text-anchor', anchor).attr('font-size', fs).attr('font-weight', '500')
            .attr('fill', 'var(--text,#222)').attr('paint-order', 'stroke')
            .attr('stroke', 'var(--bg,#fff)').attr('stroke-width', fs > 9 ? 2.4 : 1.8)
            .attr('stroke-linejoin', 'round').text(trim(node, 18));
          if (rot) t.attr('transform', 'rotate(-55,' + x + ',' + y + ')');
          return t;
        }
        mem.forEach(function (r, ri) {
          lbl(nodes[r].name, -5, ri * cs + cs * 0.72, 'end', false);
          lbl(nodes[r].name, ri * cs + cs * 0.62, -5, 'start', true);
        });
        // click matrix background for a summary
        sel.on('click', function (ev) {
          if (ev.target.tagName === 'rect' && d3.select(ev.target).style('cursor') === 'pointer') return;
          showInfo('<b>Matrix block</b><br>' + b.members.length + ' nodes<br><span style="color:var(--text3,#999)">' +
            esc(b.members.slice(0, 8).map(function (i) { return nodes[i].name; }).join(', ')) + (b.members.length > 8 ? ', …' : '') + '</span>');
        });
      } else {
        var ni = b.members[0];
        sel.append('circle').attr('r', b.r).attr('fill', '#2E9CDB').attr('stroke', '#1c6fa0').attr('stroke-width', 1.5).style('cursor', 'pointer');
        sel.append('text').attr('class', 'nx-nodelabel').attr('y', b.r + 12).attr('text-anchor', 'middle')
          .attr('font-size', 10).attr('font-weight', '500').attr('fill', 'var(--text,#222)')
          .attr('paint-order', 'stroke').attr('stroke', 'var(--bg,#fff)').attr('stroke-width', 2)
          .attr('stroke-linejoin', 'round').text(trim(nodes[ni].name, 18));
        sel.on('click', function (ev) {
          ev.stopPropagation();
          showInfo('<b>Node</b><br><b>' + esc(nodes[ni].name) + '</b><br>degree: <b>' + degree[ni] + '</b><br>connections: <b>' + Object.keys(adj[ni]).length + '</b>');
        });
      }
    }

    function restyle() {
      if (!blockSel) return;
      bridgeSel.attr('stroke-opacity', settings.linkOpacity);
      d3.selectAll(mainArea.querySelectorAll('.nx-labels, .nx-nodelabel'))
        .style('display', settings.showLabels ? null : 'none');
    }

    function trim(s, n) { s = String(s); return s.length > n ? s.slice(0, n - 1) + '…' : s; }
    function esc(s) { return String(s).replace(/[&<>"]/g, function (c) { return { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[c]; }); }

    mainArea.addEventListener('click', function (e) { if (e.target === mainArea) hideInfo(); });

    // ── Init + responsive ──────────────────────────────────────────────
    rebuild();
    var rt;
    var relayout = function () { clearTimeout(rt); rt = setTimeout(function () { fitWrap(); draw(); }, 120); };
    window.addEventListener('resize', relayout);
    if (window.ResizeObserver && wrap.parentNode) {
      var ro = new ResizeObserver(relayout);
      ro.observe(wrap.parentNode);
    }
  }
}
